{"list":[{"type":"eventStartConditional","center":{"x":40,"y":180},"triggerType":"afterRecordSaved","isInterrupting":false,"id":"y07beybblv","text":"After feedback saved","description":null,"conditionsAll":[],"conditionsAny":[],"conditionsFormula":null},{"type":"task","center":{"x":160,"y":180},"id":"qmgzrskmcs","text":"set $$recordString","actionList":[{"formula":"
// Fetch real attributes
$feedbackDescription = record\attribute('CFeedbackData', id, 'feedbackDescription');
$codingLevel1 = record\attribute('CFeedbackData', id, 'codingLevel1Name');    
$codingLevel2 = record\attribute('CFeedbackData', id, 'codingLevel2Name');    
$codingLevel3 = record\attribute('CFeedbackData', id, 'codingLevel3Name');    
$feedbackID = record\attribute('CFeedbackData', id, 'feedbackFormID');
$createdAt = record\attribute('CFeedbackData', id, 'createdAt');

// Clean the feedback description string
$feedbackDescription = string\replace($feedbackDescription, "\n", " ");
$feedbackDescription = string\replace($feedbackDescription, "\r", "");
$feedbackDescription = string\replace($feedbackDescription, '"', '-');
// Fill metadata JSON string
$metadata = string\concatenate(
    '{',
    '"created": "', $createdAt, '", ',
    '"coding_level_1": "', $codingLevel1, '", ',
    '"coding_level_2": "', $codingLevel2, '", ', 
    '"coding_level_3": "', $codingLevel3, '"',             
    '}'
);

// Fill record-level JSON string
$$recordString = string\concatenate(
    '{"content": "', $feedbackDescription, '", "id": "', $feedbackID, '", ', 
    '"metadata": ', $metadata, '}'
);","cid":0,"id":"6qk8bx37gl","type":"executeFormula"}],"description":null},{"type":"task","center":{"x":300,"y":180},"id":"g3dcslcmvk","text":"set $$codesString","actionList":[{"formula":"$ids1 = record\findMany('CCodingLevel1', 20, 'name', 'asc');
$rootCodes = list();
$i = 0;

while ($i < array\length($ids1)) {
    $id1 = array\at($ids1, $i);

    $name1 = record\attribute('CCodingLevel1', $id1, 'name');
    ifThen($name1 == null || string\length($name1) == 0, $name1 = $id1);

    // Fetch and append nameEn for Level 1 if present
    $nameEn1 = record\attribute('CCodingLevel1', $id1, 'nameEn');
    ifThen($nameEn1 != null && string\length($nameEn1) > 0, $name1 = string\concatenate($name1, ' ', $nameEn1));

    // Search for Level 2s that point to this Level 1
    $ids2 = record\findMany('CCodingLevel2', 50, 'name', 'asc', 'codingLevel1Id=', $id1);
    $nodes2 = list();
    $j = 0;

    while ($j < array\length($ids2)) {
        $id2 = array\at($ids2, $j);

        $name2 = record\attribute('CCodingLevel2', $id2, 'name');
        ifThen($name2 == null || string\length($name2) == 0, $name2 = $id2);

        // Fetch and append nameEn for Level 2 if present
        $nameEn2 = record\attribute('CCodingLevel2', $id2, 'nameEn');
        ifThen($nameEn2 != null && string\length($nameEn2) > 0, $name2 = string\concatenate($name2, ' ', $nameEn2));

        // Search for Level 3s that point to this Level 2
        $ids3 = record\findMany('CCodingLevel3', 50, 'name', 'asc', 'codingLevel2Id=', $id2);
        $nodes3 = list();
        $k = 0;

        while ($k < array\length($ids3)) {
            $id3 = array\at($ids3, $k);

            $name3 = record\attribute('CCodingLevel3', $id3, 'name');
            ifThen($name3 == null || string\length($name3) == 0, $name3 = $id3);

            // Fetch and append nameEn for Level 3 if present
            $nameEn3 = record\attribute('CCodingLevel3', $id3, 'nameEn');
            ifThen($nameEn3 != null && string\length($nameEn3) > 0, $name3 = string\concatenate($name3, ' ', $nameEn3));

            // Fetch and append description for Level 3 if present
            $desc3 = record\attribute('CCodingLevel3', $id3, 'description');
            ifThen($desc3 != null && string\length($desc3) > 0, $name3 = string\concatenate($name3, ' ', $desc3));

            $node3 = object\create();
            $node3['id'] = $id3;
            $node3['name'] = $name3;
            $node3['children'] = list();

            $nodes3 = array\push($nodes3, $node3);
            $k = $k + 1;
        }

        $node2 = object\create();
        $node2['id'] = $id2;
        $node2['name'] = $name2;
        $node2['children'] = $nodes3;

        $nodes2 = array\push($nodes2, $node2);
        $j = $j + 1;
    }

    $node1 = object\create();
    $node1['id'] = $id1;
    $node1['name'] = $name1;
    $node1['children'] = $nodes2;

    $rootCodes = array\push($rootCodes, $node1);
    $i = $i + 1;
}

$$codesString = json\encode($rootCodes);","cid":0,"id":"q4sq80yz5v","type":"executeFormula"}],"description":null},{"type":"task","center":{"x":580,"y":440},"id":"7k24bkfmi6","text":"combine $$motherPayload","actionList":[{"formula":"$motherPayload = string\concatenate(
